import{_ as t,c as i,a as s,t as o,m as a,o as l}from"./DH_pgX65.js";const n={},r={class:"min-h-screen bg-gray-50 text-gray-900"},c={class:"max-w-3xl mx-auto px-4 py-10"},d={class:"mb-4 text-sm text-gray-600"};function p(u,e){return l(),i("main",r,[s("section",c,[e[0]||(e[0]=s("h1",{class:"text-3xl font-bold mb-6"}," Politique de confidentialité – Mille Services ",-1)),s("p",d," Dernière mise à jour : "+o(new Date().toLocaleDateString()),1),e[1]||(e[1]=a('<p class="mb-6"> Cette politique de confidentialité décrit comment Mille Services collecte, utilise et protège vos informations lorsque vous utilisez nos applications et notre back‑office d’administration. </p><h2 class="text-xl font-semibold mt-6 mb-2"> 1. Données que nous collectons </h2><ul class="list-disc list-inside space-y-1 mb-4"><li><span class="font-semibold">Données de compte :</span> nom, prénom, adresse e‑mail, numéro de téléphone, rôle (particulier / prestataire / administrateur). </li><li><span class="font-semibold">Données liées aux prestations :</span> adresses, descriptions de tâches, historique de prestations. </li><li><span class="font-semibold">Données de documents prestataire :</span> pièces d’identité, casier judiciaire, certificats (via upload sécurisé). </li><li><span class="font-semibold">Données techniques :</span> logs serveur, identifiants de session, informations de navigateur. </li></ul><h2 class="text-xl font-semibold mt-6 mb-2"> 2. Utilisation de vos données </h2><p class="mb-4"> Nous utilisons vos données pour : </p><ul class="list-disc list-inside space-y-1 mb-4"><li>Créer et gérer vos comptes utilisateur.</li><li>Mettre en relation particuliers et prestataires.</li><li>Gérer les abonnements, paiements et wallets prestataire.</li><li>Assurer la conformité légale et la lutte contre la fraude.</li><li>Améliorer la qualité du service et le support client.</li></ul><h2 class="text-xl font-semibold mt-6 mb-2"> 3. Caméra et fichiers (applications mobiles) </h2><p class="mb-4"> Nos applications mobiles peuvent demander l’accès à la caméra et au stockage pour permettre : </p><ul class="list-disc list-inside space-y-1 mb-4"><li>la prise de photos de profil ou de réalisations ;</li><li>le dépôt de documents nécessaires à la vérification des prestataires.</li></ul><p class="mb-4"> Les photos et documents sont utilisés exclusivement dans le cadre de Mille Services (validation de comptes, présentation de prestations) et ne sont pas vendus à des tiers. </p><h2 class="text-xl font-semibold mt-6 mb-2"> 4. Partage de vos données </h2><p class="mb-4"> Nous ne vendons pas vos données. Elles peuvent être partagées uniquement : </p><ul class="list-disc list-inside space-y-1 mb-4"><li>avec des prestataires techniques (hébergement, e‑mailing, stockage) ;</li><li>si la loi l’exige (obligation légale, demande d’une autorité) ;</li><li>pour prévenir les fraudes ou garantir la sécurité de la plateforme.</li></ul><h2 class="text-xl font-semibold mt-6 mb-2"> 5. Durée de conservation </h2><p class="mb-4"> Les données sont conservées pendant la durée nécessaire à la fourniture du service et au respect de nos obligations légales, puis supprimées ou anonymisées. </p><h2 class="text-xl font-semibold mt-6 mb-2"> 6. Vos droits </h2><p class="mb-4"> Conformément à la réglementation applicable (notamment RGPD pour les utilisateurs en Europe), vous disposez d’un droit d’accès, de rectification, de suppression et de portabilité de vos données, ainsi que d’un droit d’opposition et de limitation du traitement. </p><h2 class="text-xl font-semibold mt-6 mb-2"> 7. Sécurité </h2><p class="mb-4"> Nous mettons en œuvre des mesures techniques et organisationnelles raisonnables pour protéger vos informations contre l’accès non autorisé, la modification, la divulgation ou la destruction. </p><h2 class="text-xl font-semibold mt-6 mb-2"> 8. Contact </h2><p class="mb-4"> Pour toute question concernant cette politique de confidentialité ou pour exercer vos droits, vous pouvez nous contacter à l’adresse suivante : <span class="font-semibold">contact@mille-services.com</span> (ou toute autre adresse officielle de Mille Services). </p><hr class="my-8"><p class="text-sm text-gray-500"> English short version available on request. This privacy policy explains how Mille Services collects and processes personal data for its mobile apps and back‑office. For any question, please contact <span class="font-semibold">contact@mille-services.com</span>. </p>',23))])])}const b=t(n,[["render",p]]);export{b as default};
